-- Rejoy: Achievements catalog and user_achievements
-- Run after 001_initial_schema.sql

create table if not exists public.achievements (
  id uuid primary key,
  symbol text not null default 'star.fill',
  title_en text not null,
  title_ru text not null,
  title_uk text not null,
  description_en text not null,
  description_ru text not null,
  description_uk text not null,
  section int not null,
  sort_order int not null default 0
);

create table if not exists public.user_achievements (
  id uuid primary key default gen_random_uuid(),
  user_id uuid references auth.users(id) on delete cascade,
  achievement_id uuid not null references public.achievements(id) on delete cascade,
  unlocked_at timestamptz not null default now(),
  local_user_id text
);

alter table public.achievements enable row level security;
alter table public.user_achievements enable row level security;

create policy "Anyone can read achievements"
  on public.achievements for select using (true);

create policy "Users can manage own user_achievements"
  on public.user_achievements for all
  using (auth.uid() = user_id or user_id is null);

create index if not exists user_achievements_user_id_idx on public.user_achievements(user_id);
create index if not exists user_achievements_achievement_id_idx on public.user_achievements(achievement_id);

-- Seed achievements
on conflict (id) do nothing;