  ('52b26c4a-6d26-4f07-93e5-f0e4bcd34ec1', 'sparkles', 'Знак Притягательности', 'Знак Притягательности', 'Знак Притягательности', 'Твоя доброта сегодня превращается в твое личное обаяние. Люди будут тянуться к тебе, чувствуя твой внутренний свет.', 'Твоя доброта сегодня превращается в твое личное обаяние. Люди будут тянуться к тебе, чувствуя твой внутренний свет.', 'Твоя доброта сегодня превращается в твое личное обаяние. Люди будут тянуться к тебе, чувствуя твой внутренний свет.', 1, 3),
  ('1c80ebca-a5ec-47d6-ba27-bcc83a12b6bc', 'heart.fill', 'Знак Комфорта', 'Знак Комфорта', 'Знак Комфорта', 'Твоя нежность к близким сегодня создает твою будущую жизнь, полную уюта, тепла и материального благополучия.', 'Твоя нежность к близким сегодня создает твою будущую жизнь, полную уюта, тепла и материального благополучия.', 'Твоя нежность к близким сегодня создает твою будущую жизнь, полную уюта, тепла и материального благополучия.', 1, 4),
